mapper.select:

select count(1)
from biz_reservation_order
where deleted = 0

  and submit_time >= #{startTime}


  and submit_time <= #{endTime}


  and department_id = #{scopeDepartmentId}


select count(1)
from biz_reservation_order
where deleted = 0
  and order_status = #{status}

  and submit_time >= #{startTime}


  and submit_time <= #{endTime}


  and department_id = #{scopeDepartmentId}

select coalesce(avg(coalesce(final_amount, 0)), 0)
from biz_reservation_order
where deleted = 0

  and submit_time >= #{startTime}


  and submit_time <= #{endTime}


  and department_id = #{scopeDepartmentId}


select count(1)
from biz_settlement_record s
left join biz_reservation_order o on o.id = s.order_id
where s.settle_status = #{status}

  and s.create_time >= #{startTime}


  and s.create_time <= #{endTime}


  and o.department_id = #{scopeDepartmentId}


select coalesce(sum(coalesce(s.final_amount, 0)), 0)
from biz_settlement_record s
left join biz_reservation_order o on o.id = s.order_id
where s.settle_status = #{status}

  and s.create_time >= #{startTime}


  and s.create_time <= #{endTime}


  and o.department_id = #{scopeDepartmentId}

select max(coalesce(nullif(i.instrument_name, ''), concat('仪器#', o.instrument_id))) as `key`, count(1) as `value` from biz_reservation_order o left join biz_instrument i on i.id = o.instrument_id where o.deleted = 0 and o.instrument_id is not null and o.order_status not in ('CANCELED', 'REJECTED')
and o.submit_time >= #{startTime}
and o.submit_time <= #{endTime}
and o.department_id = #{scopeDepartmentId}
group by o.instrument_id order by `value` desc, o.instrument_id asc limit #{limit}

select coalesce(nullif(d.dept_name, ''), '未知部门') as `key`, count(1) as `value` from biz_reservation_order o left join sys_department d on d.id = o.department_id where o.deleted = 0
and o.submit_time >= #{startTime}
and o.submit_time <= #{endTime}
and o.department_id = #{scopeDepartmentId}
group by coalesce(nullif(d.dept_name, ''), '未知部门') order by `value` desc, `key` asc

select date_format(o.submit_time, '%Y-%m-%d') as `key`, count(1) as `value` from biz_reservation_order o where o.deleted = 0 and o.submit_time is not null
and o.submit_time >= #{startTime}
and o.submit_time <= #{endTime}
and o.department_id = #{scopeDepartmentId}
group by date_format(o.submit_time, '%Y-%m-%d') order by `key` asc

select date_format(o.submit_time, '%Y-%m') as `key`, count(1) as `value` from biz_reservation_order o where o.deleted = 0 and o.submit_time is not null
and o.submit_time >= #{startTime}
and o.submit_time <= #{endTime}
and o.department_id = #{scopeDepartmentId}
group by date_format(o.submit_time, '%Y-%m') order by `key` asc

select d.id as departmentId, coalesce(nullif(d.dept_name, ''), '未命名部门') as departmentName, count(i.id) as instrumentCount, coalesce(d.sort_no, 2147483647) as sortNo from sys_department d left join biz_instrument i on i.department_id = d.id and i.deleted = 0 where d.deleted = 0
and d.id = #{scopeDepartmentId}
group by d.id, d.dept_name, d.sort_no order by instrumentCount desc, sortNo asc, d.id asc
